#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int S[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &S[i]);
        }
        qsort(S, N, sizeof(int), compare);
        int mex = 0;
        for (int i = 0; i < N; i++) {
            if (S[i] == mex) {
                mex++;
            } else if (S[i] > mex && K > 0) {
                K--;
                mex++;
            } else if (S[i] > mex && K == 0) {
                break;
            }
        }
        while (K > 0) {
            mex++;
            K--;
        }
        printf("%d\n", mex);
    }
    return 0;
}

