        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int[] S = new int[N];
            for (int i = 0; i < N; i++) {
                S[i] = sc.nextInt();
            }
            Arrays.sort(S);
            int mex = 0;
            for (int i = 0; i < N; i++) {
                if (S[i] == mex) {
                    mex++;
                } else if (S[i] > mex && K > 0) {
                    K--;
                    mex++;
                } else if (S[i] > mex && K == 0) {
                    break;
                }
            }
            while (K > 0) {
                mex++;
